    38|
    39|export default function ContentEditor() {
    40|  const [content, setContent] = useState<Record<string, unknown>>({})
    41|  const [siteId, setSiteId] = useState("default")
    42|  const [loading, setLoading] = useState(true)
    43|  const [saving, setSaving] = useState(false)
